package com.yottastudios.jira.ao;

import net.java.ao.Entity;
import net.java.ao.Preload;
import net.java.ao.schema.*;

@Preload
@Table("JIB_ISU_TEMP")
public interface IssueTemplate extends Entity {
    @AutoIncrement
    @NotNull
    @PrimaryKey("ID")
    int getID();

    @NotNull
    @Indexed
    int getTemplateId();
    void setTemplateId(int templateId);

    @StringLength(StringLength.UNLIMITED)
    String getFields();
    void setFields(String fields);

    // 旧：单个上游（兼容迁移）
    int getUpstreamIssueTemplateId();
    void setUpstreamIssueTemplateId(int upstreamIssueTemplateId);

    // 新：多个上游，使用字符串列存储（逗号分隔）
    @StringLength(StringLength.UNLIMITED)
    String getUpstreamIssueTemplateIds();
    void setUpstreamIssueTemplateIds(String upstreamIssueTemplateIds);

    int getParentIssueTemplateId();
    void setParentIssueTemplateId(int parentIssueTemplateId);

    int getOrderNo();
    void setOrderNo(int orderNo);
}

package com.yottastudios.jira.servlet;

