@Slf4j
public class JiraBotServlet extends HttpServlet {
    private static final String PLUGIN_STORAGE_KEY = "com.atlassian.plugins.yottastudios.jira.jirabot";
    private static final String LINK_TYPE_UPSTREAM = "上游任务";
    private static final String LINK_TYPE_PARENT = "父任务";

    private final Map<String, BiConsumer<HttpServletRequest, HttpServletResponse>> getRoutes = new HashMap<>();
    private final Map<String, BiConsumer<HttpServletRequest, HttpServletResponse>> postRoutes = new HashMap<>();

    @ComponentImport
    private final UserManager userManager;
    @ComponentImport
    private final LoginUriProvider loginUriProvider;
    @ComponentImport
    private final TemplateRenderer templateRenderer;
    @ComponentImport
    private final PluginSettingsFactory pluginSettingsFactory;
    @ComponentImport
    private final RequestFactory<?> requestFactory;
    @ComponentImport
    private final PageBuilderService pageBuilderService;

    private final TemplateGroupMapper templateGroupMapper;
    private final TemplateMapper templateMapper;
    private final IssueTemplateMapper issueTemplateMapper;

    @Inject
    public JiraBotServlet(UserManager userManager, LoginUriProvider loginUriProvider, TemplateRenderer templateRenderer, PluginSettingsFactory pluginSettingsFactory, RequestFactory<?> requestFactory, PageBuilderService pageBuilderService, TemplateGroupMapper templateGroupMapper, TemplateMapper templateMapper, IssueTemplateMapper issueTemplateMapper) {
        this.userManager = userManager;
        this.loginUriProvider = loginUriProvider;
        this.templateRenderer = templateRenderer;
        this.pluginSettingsFactory = pluginSettingsFactory;
        this.requestFactory = requestFactory;
        this.pageBuilderService = pageBuilderService;
        this.templateGroupMapper = templateGroupMapper;
        this.templateMapper = templateMapper;
        this.issueTemplateMapper = issueTemplateMapper;

        initRoutes();
    }

    @FunctionalInterface
    private interface RequestHandler {
        void handle(HttpServletRequest request, HttpServletResponse response) throws Exception;
    }

    private BiConsumer<HttpServletRequest, HttpServletResponse> withExceptionHandling(RequestHandler handler) {
        return (request, response) -> {
            try {
                handler.handle(request, response);
            } catch (Exception e) {
                log.warn("Error handling request: " + e.getMessage());
                e.printStackTrace();
            }
        };
    }



    private void initRoutes() {
        // GET
        getRoutes.put("/getUserInfo", jsonEndpoint(this::getUserInfo));
        getRoutes.put("/", withExceptionHandling(this::renderHomePage));
        getRoutes.put("/api-docs", withExceptionHandling(this::renderApiDocs));
        getRoutes.put("/blank", withExceptionHandling(this::renderBlankPage));

        // POST
        postRoutes.put("/getUserInfo", jsonEndpoint(this::getUserInfo));
        postRoutes.put("/issue/create", jsonEndpoint(this::createJiraIssue));
        postRoutes.put("/issue/create/batch", jsonEndpoint(this::batchCreateJiraIssues));
        // 仅测试合作任务使用，有问题进行回退
        postRoutes.put("/issue/create/batch2", jsonEndpoint(this::batchCreateJiraIssues2));
        postRoutes.put("/issue/create/v2", jsonEndpoint(this::createJiraIssueV2));
        postRoutes.put("/template-group/create", jsonEndpoint(this::createTemplateGroup));
        postRoutes.put("/template-group/update", jsonEndpoint(this::updateTemplateGroup));
        postRoutes.put("/template-group/delete", jsonEndpoint(this::deleteTemplateGroup));
        postRoutes.put("/template-group/list", jsonEndpoint(this::listTemplateGroups));
        postRoutes.put("/template/create", jsonEndpoint(this::createTemplate));
        postRoutes.put("/template/update", jsonEndpoint(this::updateTemplate));
        postRoutes.put("/template/delete", jsonEndpoint(this::deleteTemplate));
        postRoutes.put("/template/listByGroupId", jsonEndpoint(this::listTemplatesByGroupId));
        postRoutes.put("/issue-template/create", jsonEndpoint(this::createIssueTemplate));
        postRoutes.put("/issue-template/update", jsonEndpoint(this::updateIssueTemplate));
        postRoutes.put("/issue-template/delete", jsonEndpoint(this::deleteIssueTemplate));
        postRoutes.put("/issue-template/listByTemplate", jsonEndpoint(this::listIssueTemplatesByTemplate));
    }

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) {
        if (handleRequest(request, response, getRoutes)) {
            return;
        }

        try {
            renderHomePage(request, response);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws  IOException {
        if (handleRequest(request, response, postRoutes)) {
            return;
        }

        response.sendRedirect(request.getContextPath() + "/plugins/servlet/jiraBot");
    }

    private boolean handleRequest(HttpServletRequest request, HttpServletResponse response,
                                  Map<String, BiConsumer<HttpServletRequest, HttpServletResponse>> routes) {
        String pathInfo = request.getPathInfo();
        if (pathInfo == null) {
            pathInfo = "/";
        }

        BiConsumer<HttpServletRequest, HttpServletResponse> handler = routes.get(pathInfo);
        if (handler != null) {
            handler.accept(request, response);
            return true;
        }

        return false;
    }

    private void renderHomePage(HttpServletRequest request, HttpServletResponse response) throws Exception {
        templateRenderer.render("home.vm", response.getWriter());
    }

    private void renderApiDocs(HttpServletRequest request, HttpServletResponse response) throws Exception {
        templateRenderer.render("api-docs.vm", response.getWriter());
    }

    private void renderBlankPage(HttpServletRequest request, HttpServletResponse response) throws Exception {
        templateRenderer.render("blank.vm", response.getWriter());
    }

    private SimpleUserInfo getUserInfo(HttpServletRequest request) {
        UserProfile user = userManager.getRemoteUser(request);

        if (user == null) {
            log.warn("无法获取用户信息，userProfile为null");
            throw new RuntimeException("无法获取用户信息");
        }

        JSONObject userInfo = new JSONObject();
        userInfo.put("username", user.getUsername());
        userInfo.put("displayName", user.getFullName());
        userInfo.put("email", user.getEmail());

        return new SimpleUserInfo(user.getUsername(), user.getFullName(), user.getEmail());
    }

    @Data
    @AllArgsConstructor
    @NoArgsConstructor
    private class SimpleUserInfo {
        private String username;
        private String displayName;
        private String email;
    }

    @Data
    @AllArgsConstructor
    private static class CreatedIssueInfo {
        private String issueKey;
        private Long issueId;
    }

    private TemplateGroupVo createTemplateGroup(HttpServletRequest request) throws Exception {
        UserProfile user = userManager.getRemoteUser(request);
        if (user == null) throw new RuntimeException("未登录");

        TemplateGroupCreateRo ro = readJsonBody(request, TemplateGroupCreateRo.class);
        if (ro == null || ro.getName() == null || ro.getName().trim().isEmpty()) {
            throw new RuntimeException("名称不能为空");
        }
        TemplateGroup created = templateGroupMapper.create(ro.getName().trim());
        return TemplateGroupVo.from(created);
    }

    private TemplateGroupVo updateTemplateGroup(HttpServletRequest request) throws Exception {
        UserProfile user = userManager.getRemoteUser(request);
        if (user == null) throw new RuntimeException("未登录");

        TemplateGroupUpdateRo ro = readJsonBody(request, TemplateGroupUpdateRo.class);
        if (ro == null || ro.getId() <= 0) throw new RuntimeException("非法ID");
        if (ro.getName() == null || ro.getName().trim().isEmpty()) throw new RuntimeException("名称不能为空");
        TemplateGroup updated = templateGroupMapper.update(ro.getId(), ro.getName().trim());
        if (updated == null) throw new RuntimeException("记录不存在");
        return TemplateGroupVo.from(updated);
    }

    private TemplateGroupDeleteVo deleteTemplateGroup(HttpServletRequest request) throws Exception {
        UserProfile user = userManager.getRemoteUser(request);
        if (user == null) throw new RuntimeException("未登录");

        TemplateGroupDeleteRo ro = readJsonBody(request, TemplateGroupDeleteRo.class);
        if (ro == null || ro.getId() <= 0) throw new RuntimeException("非法ID");
        boolean success = templateGroupMapper.deleteById(ro.getId());
        return new TemplateGroupDeleteVo(success);
    }

    private List<TemplateGroupVo> listTemplateGroups(HttpServletRequest request) throws Exception {
        UserProfile user = userManager.getRemoteUser(request);
        if (user == null) throw new RuntimeException("未登录");

        readJsonBody(request, TemplateGroupListRo.class);

        TemplateGroup[] all = templateGroupMapper.list();
        List<TemplateGroupVo> groups = new ArrayList<>();
        for (TemplateGroup g : all) groups.add(TemplateGroupVo.from(g));
        return groups;
    }



    private CreatedIssueInfo createJiraIssue(HttpServletRequest request) throws Exception {
        // 用户校验与上下文
        UserProfile userProfile = userManager.getRemoteUser(request);
        if (userProfile == null) {
            throw new RuntimeException("未登录");
        }
        ApplicationUser applicationUser = ComponentAccessor.getUserManager().getUserByName(userProfile.getUsername());
        if (applicationUser == null) {
            throw new RuntimeException("无法获取应用用户");
        }
        JiraAuthenticationContext jiraAuthenticationContext = ComponentAccessor.getJiraAuthenticationContext();
        jiraAuthenticationContext.setLoggedInUser(applicationUser);

        CreateJiraIssueRo ro = readJsonBody(request, CreateJiraIssueRo.class);
        Map<String, Object> fields = ro.getFields();
        if (fields == null) {
            throw new RuntimeException("请求体字段不能为空");
        }

        Issue created = createIssueWithParameters(applicationUser, fields);

        // 创建链接
        if (!isBlank(ro.getTargetLinkIssueKey()) && !isBlank(ro.getLinkTypeName())) {
            createIssueLink(created.getKey(), ro.getTargetLinkIssueKey(), ro.getLinkTypeName(), applicationUser);
        }

        return new CreatedIssueInfo(created.getKey(), created.getId());
    }

    private CreatedIssueInfo createJiraIssueV2(HttpServletRequest request) throws Exception {
        UserProfile userProfile = userManager.getRemoteUser(request);
        if (userProfile == null) throw new RuntimeException("未登录");
        ApplicationUser applicationUser = ComponentAccessor.getUserManager().getUserByName(userProfile.getUsername());
        if (applicationUser == null) throw new RuntimeException("无法获取应用用户");
        JiraAuthenticationContext jiraAuthenticationContext = ComponentAccessor.getJiraAuthenticationContext();
        jiraAuthenticationContext.setLoggedInUser(applicationUser);

        String body = readBody(request);
        if (body == null || body.trim().isEmpty()) throw new RuntimeException("请求体不能为空");
        JSONObject obj = new JSONObject(body);
        CreateJiraIssueV2Ro ro = CreateJiraIssueV2Ro.parseCreateJiraIssueV2(obj);
        if (ro.getFields() == null) throw new RuntimeException("请求体字段不能为空");

        Issue created = createIssueWithParameters(applicationUser, ro.getFields());

        if (ro.getLinks() != null) {
            for (com.yottastudios.jira.ro.LinkCreateRo link : ro.getLinks()) {
                if (link == null) continue;
                if (isBlank(link.getLinkTypeName()) || isBlank(link.getTargetIssueKey())) continue;
                createIssueLink(created.getKey(), link.getTargetIssueKey(), link.getLinkTypeName(), applicationUser);
            }
        }

        return new CreatedIssueInfo(created.getKey(), created.getId());
    }

    private List<CreatedIssueInfo> batchCreateJiraIssues(HttpServletRequest request) throws Exception {
        UserProfile userProfile = userManager.getRemoteUser(request);
        if (userProfile == null) throw new RuntimeException("未登录");
        ApplicationUser applicationUser = ComponentAccessor.getUserManager().getUserByName(userProfile.getUsername());
        if (applicationUser == null) throw new RuntimeException("无法获取应用用户");
        JiraAuthenticationContext jiraAuthenticationContext = ComponentAccessor.getJiraAuthenticationContext();
        jiraAuthenticationContext.setLoggedInUser(applicationUser);

        String body = readBody(request);
        if (body == null || body.trim().isEmpty()) throw new RuntimeException("请求体不能为空");
        JSONObject root = new JSONObject(body);
        if (!root.has("issues")) throw new RuntimeException("issues不能为空");
        JSONArray arr = root.getJSONArray("issues");
        if (arr.length() == 0) throw new RuntimeException("issues不能为空");

        List<CreateJiraIssueV2Ro> issueRos = new ArrayList<>();
        for (int i = 0; i < arr.length(); i++) {
            Object item = arr.get(i);
            if (!(item instanceof JSONObject)) throw new RuntimeException("issues项必须为对象");
            issueRos.add(CreateJiraIssueV2Ro.parseCreateJiraIssueV2((JSONObject) item));
        }

        for (CreateJiraIssueV2Ro item : issueRos) {
            if (item.getIssueTemplateId() == null) throw new RuntimeException("每个issue必须包含issueTemplateId");
            if (item.getFields() == null) throw new RuntimeException("请求体字段不能为空");
        }

        Map<Long, CreateJiraIssueV2Ro> templateIdToItem = new LinkedHashMap<>();
        for (CreateJiraIssueV2Ro item : issueRos) {
            Long id = item.getIssueTemplateId();
            if (templateIdToItem.containsKey(id)) throw new RuntimeException("issueTemplateId重复: " + id);
            templateIdToItem.put(id, item);
        }

        Map<Long, List<Long>> edges = new HashMap<>();
        Map<Long, Integer> indegree = new HashMap<>();
        for (Long id : templateIdToItem.keySet()) indegree.put(id, 0);
        for (CreateJiraIssueV2Ro item : issueRos) {
            Long parent = item.getParentIssueTemplateId();
            if (parent != null) {
                if (!templateIdToItem.containsKey(parent)) throw new RuntimeException("未找到依赖的issueTemplateId: " + parent);
                edges.computeIfAbsent(parent, k -> new ArrayList<>()).add(item.getIssueTemplateId());
                indegree.put(item.getIssueTemplateId(), indegree.get(item.getIssueTemplateId()) + 1);
            }
            List<Long> ups = item.getUpstreamIssueTemplateIds();
            if (ups != null) {
                for (Long up : ups) {
                    if (up == null) continue;
                    if (!templateIdToItem.containsKey(up)) throw new RuntimeException("未找到依赖的issueTemplateId: " + up);
                    edges.computeIfAbsent(up, k -> new ArrayList<>()).add(item.getIssueTemplateId());
                    indegree.put(item.getIssueTemplateId(), indegree.get(item.getIssueTemplateId()) + 1);
                }
            }
        }

        Set<Long> nodesWithChildren = new HashSet<>(edges.keySet());
        Set<Long> nodesReferencedAsChild = new HashSet<>();
        for (List<Long> children : edges.values()) nodesReferencedAsChild.addAll(children);
        Set<Long> inGraph = new HashSet<>();
        inGraph.addAll(nodesWithChildren);
        inGraph.addAll(nodesReferencedAsChild);

        Deque<Long> queue = new ArrayDeque<>();
        for (Long id : inGraph) if (indegree.get(id) == 0) queue.addLast(id);
        List<Long> topoOrder = new ArrayList<>();
        while (!queue.isEmpty()) {
            Long u = queue.removeFirst();
            topoOrder.add(u);
            List<Long> children = edges.get(u);
            if (children == null || children.isEmpty()) continue;
            for (Long v : children) {
                int d = indegree.get(v) - 1;
                indegree.put(v, d);
                if (d == 0) queue.addLast(v);
            }
        }
        if (topoOrder.size() != inGraph.size()) throw new RuntimeException("存在循环依赖，请检查上游/父任务设置");

        List<Long> standalone = new ArrayList<>();
        for (CreateJiraIssueV2Ro item : issueRos) {
            Long id = item.getIssueTemplateId();
            boolean noParent = item.getParentIssueTemplateId() == null;
            List<Long> ups = item.getUpstreamIssueTemplateIds();
            boolean noUpstreams = ups == null || ups.isEmpty();
            if (noParent && noUpstreams && !inGraph.contains(id)) standalone.add(id);
        }
        List<Long> orderedIds = new ArrayList<>();
        orderedIds.addAll(topoOrder);
        orderedIds.addAll(standalone);

        String dependencyTreeLog = renderDependencyForest(edges, inGraph, standalone);
        log.error("批量创建依赖关系树:\n{}", dependencyTreeLog);

        for (Long id : orderedIds) {
            CreateJiraIssueV2Ro item = templateIdToItem.get(id);
            validateIssueFields(applicationUser, item.getFields());
        }

        Map<Long, String> templateIdToIssueKey = new HashMap<>();
        List<CreatedIssueInfo> results = new ArrayList<>();
        for (Long id : orderedIds) {
            CreateJiraIssueV2Ro item = templateIdToItem.get(id);
            Map<String, Object> fields = item.getFields();

            Issue created = createIssueWithParameters(applicationUser, fields);

            Long parent = item.getParentIssueTemplateId();
            if (parent != null) {
                String parentKey = templateIdToIssueKey.get(parent);
                if (parentKey == null) throw new RuntimeException("内部错误：未找到依赖创建结果: " + parent);
                createIssueLink(created.getKey(), parentKey, LINK_TYPE_PARENT, applicationUser);
            }

            List<Long> ups = item.getUpstreamIssueTemplateIds();
            if (ups != null) {
                for (Long up : ups) {
                    if (up == null) continue;
                    String upKey = templateIdToIssueKey.get(up);
                    if (upKey == null) throw new RuntimeException("内部错误：未找到依赖创建结果: " + up);
                    createIssueLink(created.getKey(), upKey, LINK_TYPE_UPSTREAM, applicationUser);
                }
            }

            if (item.getLinks() != null) {
                Set<String> autoPairs = new HashSet<>();
                if (parent != null) autoPairs.add(LINK_TYPE_PARENT + "@" + templateIdToIssueKey.get(parent));
                if (ups != null) {
                    for (Long up : ups) {
                        if (up == null) continue;
                        String upKey = templateIdToIssueKey.get(up);
                        if (upKey != null) autoPairs.add(LINK_TYPE_UPSTREAM + "@" + upKey);
                    }
                }
                for (LinkCreateRo link : item.getLinks()) {
                    if (link == null) continue;
                    String type = link.getLinkTypeName();
                    String tgt = link.getTargetIssueKey();
                    if (isBlank(type) || isBlank(tgt)) continue;
                    String pair = type + "@" + tgt;
                    if (autoPairs.contains(pair)) continue;
                    createIssueLink(created.getKey(), tgt, type, applicationUser);
                }
            }

            templateIdToIssueKey.put(id, created.getKey());
            results.add(new CreatedIssueInfo(created.getKey(), created.getId()));
        }
        return results;
    }




    private List<CreatedIssueInfo> batchCreateJiraIssues2(HttpServletRequest request) throws Exception {
        UserProfile userProfile = userManager.getRemoteUser(request);
        if (userProfile == null) throw new RuntimeException("未登录");
        ApplicationUser applicationUser = ComponentAccessor.getUserManager().getUserByName(userProfile.getUsername());
        if (applicationUser == null) throw new RuntimeException("无法获取应用用户");
        JiraAuthenticationContext jiraAuthenticationContext = ComponentAccessor.getJiraAuthenticationContext();
        jiraAuthenticationContext.setLoggedInUser(applicationUser);

        String body = readBody(request);
        if (body == null || body.trim().isEmpty()) throw new RuntimeException("请求体不能为空");
        JSONObject root = new JSONObject(body);
        if (!root.has("issues")) throw new RuntimeException("issues不能为空");
        JSONArray arr = root.getJSONArray("issues");
        if (arr.length() == 0) throw new RuntimeException("issues不能为空");

        List<CreateJiraIssueV2Ro> issueRos = new ArrayList<>();
        for (int i = 0; i < arr.length(); i++) {
            Object item = arr.get(i);
            if (!(item instanceof JSONObject)) throw new RuntimeException("issues项必须为对象");
            // 假如负责组字段传了多个组，进行一次拆分 fields customfield_10403
            List<JSONObject> transJsonList = transJsonList(item);
            for (JSONObject transJson : transJsonList) {
                issueRos.add(CreateJiraIssueV2Ro.parseCreateJiraIssueV2(transJson));
            }
        }

        for (CreateJiraIssueV2Ro item : issueRos) {
            if (item.getIssueTemplateId() == null) throw new RuntimeException("每个issue必须包含issueTemplateId");
            if (item.getFields() == null) throw new RuntimeException("请求体字段不能为空");
        }

        Map<Long, CreateJiraIssueV2Ro> templateIdToItem = new LinkedHashMap<>();
        for (CreateJiraIssueV2Ro item : issueRos) {
            Long id = item.getIssueTemplateId();
            if (templateIdToItem.containsKey(id)) throw new RuntimeException("issueTemplateId重复: " + id);
            templateIdToItem.put(id, item);
        }

        Map<Long, List<Long>> edges = new HashMap<>();
        Map<Long, Integer> indegree = new HashMap<>();
        for (Long id : templateIdToItem.keySet()) indegree.put(id, 0);
        for (CreateJiraIssueV2Ro item : issueRos) {
            Long parent = item.getParentIssueTemplateId();
            if (parent != null) {
                if (!templateIdToItem.containsKey(parent)) throw new RuntimeException("未找到依赖的issueTemplateId: " + parent);
                edges.computeIfAbsent(parent, k -> new ArrayList<>()).add(item.getIssueTemplateId());
                indegree.put(item.getIssueTemplateId(), indegree.get(item.getIssueTemplateId()) + 1);
            }
            List<Long> ups = item.getUpstreamIssueTemplateIds();
            if (ups != null) {
                for (Long up : ups) {
                    if (up == null) continue;
                    if (!templateIdToItem.containsKey(up)) throw new RuntimeException("未找到依赖的issueTemplateId: " + up);
                    edges.computeIfAbsent(up, k -> new ArrayList<>()).add(item.getIssueTemplateId());
                    indegree.put(item.getIssueTemplateId(), indegree.get(item.getIssueTemplateId()) + 1);
                }
            }
        }

        Set<Long> nodesWithChildren = new HashSet<>(edges.keySet());
        Set<Long> nodesReferencedAsChild = new HashSet<>();
        for (List<Long> children : edges.values()) nodesReferencedAsChild.addAll(children);
        Set<Long> inGraph = new HashSet<>();
        inGraph.addAll(nodesWithChildren);
        inGraph.addAll(nodesReferencedAsChild);

        Deque<Long> queue = new ArrayDeque<>();
        for (Long id : inGraph) if (indegree.get(id) == 0) queue.addLast(id);
        List<Long> topoOrder = new ArrayList<>();
        while (!queue.isEmpty()) {
            Long u = queue.removeFirst();
            topoOrder.add(u);
            List<Long> children = edges.get(u);
            if (children == null || children.isEmpty()) continue;
            for (Long v : children) {
                int d = indegree.get(v) - 1;
                indegree.put(v, d);
                if (d == 0) queue.addLast(v);
            }
        }
        if (topoOrder.size() != inGraph.size()) throw new RuntimeException("存在循环依赖，请检查上游/父任务设置");

        List<Long> standalone = new ArrayList<>();
        for (CreateJiraIssueV2Ro item : issueRos) {
            Long id = item.getIssueTemplateId();
            boolean noParent = item.getParentIssueTemplateId() == null;
            List<Long> ups = item.getUpstreamIssueTemplateIds();
            boolean noUpstreams = ups == null || ups.isEmpty();
            if (noParent && noUpstreams && !inGraph.contains(id)) standalone.add(id);
        }
        List<Long> orderedIds = new ArrayList<>();
        orderedIds.addAll(topoOrder);
        orderedIds.addAll(standalone);

        String dependencyTreeLog = renderDependencyForest(edges, inGraph, standalone);
        log.error("批量创建依赖关系树:\n{}", dependencyTreeLog);

        for (Long id : orderedIds) {
            CreateJiraIssueV2Ro item = templateIdToItem.get(id);
            validateIssueFields(applicationUser, item.getFields());
        }

        Map<Long, String> templateIdToIssueKey = new HashMap<>();
        Map<String, Map<String, Object>> specialFields = new HashMap<>();
        Map<String, Issue> issueMap = new HashMap<>();
        List<CreatedIssueInfo> results = new ArrayList<>();
        for (Long id : orderedIds) {
            CreateJiraIssueV2Ro item = templateIdToItem.get(id);
            Map<String, Object> fields = item.getFields();
            // 此处对fields做特殊处理，指定的fields假如不合预设类型，会被在fields移除
            Map<String, Object> specialMap = filterSpecialFields(fields);
            Issue created = createIssueWithParameters(applicationUser, fields);
            specialFields.put(created.getKey(),  specialMap);
            issueMap.put(created.getKey(), created);

            Long parent = item.getParentIssueTemplateId();
            if (parent != null) {
                String parentKey = templateIdToIssueKey.get(parent);
                if (parentKey == null) throw new RuntimeException("内部错误：未找到依赖创建结果: " + parent);
                createIssueLink(created.getKey(), parentKey, LINK_TYPE_PARENT, applicationUser);
            }

            List<Long> ups = item.getUpstreamIssueTemplateIds();
            if (ups != null) {
                for (Long up : ups) {
                    if (up == null) continue;
                    String upKey = templateIdToIssueKey.get(up);
                    if (upKey == null) throw new RuntimeException("内部错误：未找到依赖创建结果: " + up);
                    createIssueLink(created.getKey(), upKey, LINK_TYPE_UPSTREAM, applicationUser);
                }
            }

            if (item.getLinks() != null) {
                Set<String> autoPairs = new HashSet<>();
                if (parent != null) autoPairs.add(LINK_TYPE_PARENT + "@" + templateIdToIssueKey.get(parent));
                if (ups != null) {
                    for (Long up : ups) {
                        if (up == null) continue;
                        String upKey = templateIdToIssueKey.get(up);
                        if (upKey != null) autoPairs.add(LINK_TYPE_UPSTREAM + "@" + upKey);
                    }
                }
                for (LinkCreateRo link : item.getLinks()) {
                    if (link == null) continue;
                    String type = link.getLinkTypeName();
                    String tgt = link.getTargetIssueKey();
                    if (isBlank(type) || isBlank(tgt)) continue;
                    String pair = type + "@" + tgt;
                    if (autoPairs.contains(pair)) continue;
                    createIssueLink(created.getKey(), tgt, type, applicationUser);
                }
            }

            templateIdToIssueKey.put(id, created.getKey());
            results.add(new CreatedIssueInfo(created.getKey(), created.getId()));
        }

        return results;
    }

    private List<JSONObject> transJsonList(Object item) {
        List<JSONObject> resultList = new ArrayList<>();

        log.warn("=== 开始处理单个issue对象 ===");
        log.warn("输入的issue对象: {}", item);

        try {
            JSONObject issue = (JSONObject) item;
            JSONObject fields = issue.getJSONObject("fields");

            if (fields == null || !fields.keySet().contains("customfield_10403")) {
                log.warn("issue的fields字段为空，直接返回原对象");
                resultList.add(issue);
                return resultList;
            }

            log.warn("fields字段内容: {}", fields);

            // 获取项目键列表（从customfield_10403）
            String customField10403 = fields.getString("customfield_10403");
            log.warn("customfield_10403字段值: {}", customField10403);

            if (customField10403 == null || customField10403.trim().isEmpty()) {
                log.warn("customfield_10403字段为空，直接返回原对象");
                resultList.add(issue);
                return resultList;
            }

            // 按逗号分割项目键
            String[] projectKeys = customField10403.split(",");
            log.warn("分割后的项目键数组: {}", Arrays.toString(projectKeys));

            // 需要特殊处理的字段名
            String[] targetFields = {"customfield_11008", "customfield_11026",
                    "customfield_11006", "customfield_11004"};

            // 为每个项目键创建一个新的JSON对象
            for (String projectKey : projectKeys) {
                projectKey = projectKey.trim();
                log.warn("处理项目键: '{}'", projectKey);

                // 复制整个issue对象，保留所有原有字段
                JSONObject newJson = deepCopyJson(issue);
                JSONObject newFields = newJson.getJSONObject("fields");

                // 设置customfield_10403为当前项目键
                newFields.put("customfield_10403", projectKey);

                // 处理目标字段
                for (String fieldName : targetFields) {
                    if (!fields.has(fieldName)){
                        continue;
                    }
                    Object fieldValue = fields.get(fieldName);
                    String processedValue = processFieldForProjectKey(fieldValue, projectKey);
                    newFields.put(fieldName, processedValue);
                    log.warn("字段'{}'处理完成: {}", fieldName, processedValue);
                }
                // 随机生成模板id
                Random random = new Random();
                newJson.put("issueTemplateId", Math.abs(random.nextLong()));

                log.warn("生成的新对象: {}", newJson);
                resultList.add(newJson);
            }

            log.warn("处理完成，从1个对象生成了{}个对象", resultList.size());

        } catch (Exception e) {
            log.error("处理issue对象时发生错误: {}", e.getMessage(), e);
            log.error("出错的输入数据: {}", item);
        }

        return resultList;
    }

    /**
     * 根据项目键处理字段值
     * 从数组中找到以项目键开头的值，去掉前缀返回
     */
    private String processFieldForProjectKey(Object fieldValue, String projectKey) {
        log.warn("      ~~~> 开始处理字段值匹配，项目键: '{}'", projectKey);
        log.warn("      ~~~> 输入字段值: {} (类型: {})", fieldValue, fieldValue != null ? fieldValue.getClass().getSimpleName() : "null");

        if (fieldValue == null) {
            log.warn("      ~~~> 字段值为null，返回空字符串");
            return "";
        }

        try {
            List<String> valueList = new ArrayList<>();

            // 解析字段值为字符串数组
            if (fieldValue instanceof JSONArray) {
                log.warn("      ~~~> 字段值是JSONArray类型");
                JSONArray array = (JSONArray) fieldValue;
                for (int i = 0; i < array.length(); i++) {
                    Object item = array.get(i);
                    if (item != null) {
                        valueList.add(item.toString());
                        log.warn("      ~~~> 从JSONArray中提取值[{}]: '{}'", i, item.toString());
                    }
                }
            } else if (fieldValue instanceof List) {
                log.warn("      ~~~> 字段值是List类型");
                List<?> list = (List<?>) fieldValue;
                for (int i = 0; i < list.size(); i++) {
                    Object item = list.get(i);
                    if (item != null) {
                        valueList.add(item.toString());
                        log.warn("      ~~~> 从List中提取值[{}]: '{}'", i, item.toString());
                    }
                }
            } else if (fieldValue instanceof Object[]) {
                log.warn("      ~~~> 字段值是Object[]类型");
                Object[] array = (Object[]) fieldValue;
                for (int i = 0; i < array.length; i++) {
                    Object item = array[i];
                    if (item != null) {
                        valueList.add(item.toString());
                        log.warn("      ~~~> 从Object[]中提取值[{}]: '{}'", i, item.toString());
                    }
                }
            } else {
                log.warn("      ~~~> 字段值是单个值类型");
                valueList.add(fieldValue.toString());
                log.warn("      ~~~> 单个值: '{}'", fieldValue.toString());
            }

            log.warn("      ~~~> 解析完成，值列表: {}", valueList);

            // 在数组中查找以当前项目键开头的值
            String prefix = projectKey + "-";
            log.warn("      ~~~> 查找前缀: '{}'", prefix);

            for (int i = 0; i < valueList.size(); i++) {
                String value = valueList.get(i);
                log.warn("      ~~~> 检查值[{}]: '{}' 是否以前缀'{}'开头", i, value, prefix);

                if (value != null && value.startsWith(prefix)) {
                    String result = value.substring(prefix.length());
                    log.warn("      ~~~> ✓ 找到匹配值！原值: '{}' -> 去前缀后: '{}'", value, result);
                    return result;
                }
            }

            log.warn("      ~~~> ✗ 没找到以'{}'开头的匹配值，返回空字符串", prefix);
            return "";

        } catch (Exception e) {
            log.error("      ~~~> 处理字段值时发生错误，字段值: {}, 项目键: {}, 错误: {}",
                    fieldValue, projectKey, e.getMessage(), e);
            return "";
        }
    }

    /**
     * JSON深拷贝方法，保留所有字段
     */
    private JSONObject deepCopyJson(JSONObject original) {
        log.debug("开始深拷贝JSON对象，原对象键数量: {}", original.keySet().size());

        JSONObject copy = new JSONObject();

        // 遍历原对象的所有键值对
        for (String key : original.keySet()) {
            Object value = original.get(key);
            log.debug("拷贝字段 '{}': {} (类型: {})", key, value, value != null ? value.getClass().getSimpleName() : "null");

            if (value instanceof JSONObject) {
                log.debug("字段'{}'是JSONObject，进行递归拷贝", key);
                copy.put(key, deepCopyJson((JSONObject) value));
            } else if (value instanceof JSONArray) {
                log.debug("字段'{}'是JSONArray，进行数组拷贝", key);
                JSONArray originalArray = (JSONArray) value;
                JSONArray copyArray = new JSONArray();
                for (int i = 0; i < originalArray.length(); i++) {
                    Object arrayItem = originalArray.get(i);
                    if (arrayItem instanceof JSONObject) {
                        copyArray.put(deepCopyJson((JSONObject) arrayItem));
                    } else {
                        copyArray.put(arrayItem);
                    }
                }
                copy.put(key, copyArray);
            } else {
                log.debug("字段'{}'是基本类型，直接拷贝", key);
                copy.put(key, value);
            }
        }

        log.debug("深拷贝完成，新对象键数量: {}", copy.keySet().size());
        return copy;
    }





    private List<Issue> findCooperationLinkedIssue(Issue issue) {
        IssueLinkManager issueLinkManager = ComponentAccessor.getIssueLinkManager();
        List<Issue> issueList = new ArrayList<>();

