                    }
                }
            });
        }

        return issueList;
    }


    public Map<String, Map<String, Object>> transformDataSimple(Map<String, Map<String, Object>> originalData) {
        Map<String, Map<String, Object>> result = new HashMap<>();

        for (Map.Entry<String, Map<String, Object>> entry : originalData.entrySet()) {
            String issueKey = entry.getKey(); // "PX-556"
            Map<String, Object> fields = entry.getValue();

            Map<String, Object> newStructure = new HashMap<>();

            // 遍历所有字段
            for (Map.Entry<String, Object> fieldEntry : fields.entrySet()) {
                String fieldName = fieldEntry.getKey(); // "customfield_11004"
                Object fieldValue = fieldEntry.getValue(); // 这个值是一个string数组[PXTL-nuoyan,PX-feibai]

                // 解析字段值，提取groupname和username
                List<String> parsedData = parseFieldValue(fieldValue);
                parsedData.forEach(data -> {
                    String[] splitData = data.split("-");
                    if (splitData.length != 2){
                        return;
                    }
                    String groupname = splitData[0];
                    String username = splitData[1];
                    // 只有groupname和username都不为空时才处理
                    if (groupname != null && !groupname.trim().isEmpty() &&
                            username != null && !username.trim().isEmpty()) {

                        if (newStructure.containsKey(groupname)){
                            Object object = newStructure.get(groupname);
                            if (object instanceof Map) {
                                @SuppressWarnings("unchecked")
                                Map<String, String> valueMap = (Map<String, String>) object;
                                valueMap.put(fieldName, username);
                            }
                        } else {
                            Map<String, String> valueMap = new HashMap<>();
                            valueMap.put(fieldName, username);
                            newStructure.put(groupname, valueMap);
                        }
                    }
                });
            }
            result.put(issueKey, newStructure);
        }

        return result;
    }


    public List<String> parseFieldValue(Object fieldValue) {
        List<String> result = new ArrayList<>();

        if (fieldValue == null) {
            return result;
        }

        // 数组类型
        if (fieldValue instanceof Object[]) {
            Object[] array = (Object[]) fieldValue;
            for (Object item : array) {
                if (item != null) {
                    result.add(item.toString());
                }
            }
        }
        // 集合类型
        else if (fieldValue instanceof Collection) {
            Collection<?> collection = (Collection<?>) fieldValue;
            for (Object item : collection) {
                if (item != null) {
                    result.add(item.toString());
                }
            }
        }
        // 字符串类型
        else {
            result.add(fieldValue.toString());
        }

        return result;
    }


    private Map<String, Object> filterSpecialFields(Map<String, Object> fields) {
        Map<String, Object> specialFields = new HashMap<>();
        // customfield_11008 承接组pm  customfield_11026 承接组qa customfield_11006 承接组程序 customfield_11004 承接组策划
        List<String> specialKeys = Arrays.asList("customfield_11008","customfield_11026","customfield_11006","customfield_11004");

        if (fields != null) {
            fields.forEach((key, value) -> {
                if (key != null && specialKeys.contains(key) && value != null) {
                    specialFields.put(key, value);
                }
            });
            specialFields.forEach(fields::remove);
        }

        return specialFields;
    }

    private String renderDependencyForest(Map<Long, List<Long>> edges, Set<Long> inGraph, List<Long> standalone) {
        StringBuilder sb = new StringBuilder();
        Set<Long> referenced = new HashSet<>();
        for (List<Long> children : edges.values()) referenced.addAll(children);
        List<Long> roots = new ArrayList<>();
        for (Long id : inGraph) if (!referenced.contains(id)) roots.add(id);

        if (!roots.isEmpty()) sb.append("依赖树:\n");
        for (Long root : roots) appendDependencyTree(root, edges, "", sb);

        if (!standalone.isEmpty()) {
            if (sb.length() > 0) sb.append('\n');
            sb.append("独立节点(无上下游): ");
            for (int i = 0; i < standalone.size(); i++) {
                if (i > 0) sb.append(", ");
                sb.append(standalone.get(i));
            }
        }
        return sb.toString();
    }

    private void appendDependencyTree(Long nodeId, Map<Long, List<Long>> edges, String indent, StringBuilder sb) {
        sb.append(indent).append("- ").append(nodeId).append('\n');
        List<Long> children = edges.get(nodeId);
        if (children == null || children.isEmpty()) return;
        String childIndent = indent + "  ";
        for (Long child : children) appendDependencyTree(child, edges, childIndent, sb);
    }

