    private void processFieldsToParameters(Map<String, Object> fields, IssueInputParameters issueInputParameters) {
        ProjectManager projectManager = ComponentAccessor.getProjectManager();
        ConstantsManager constantsManager = ComponentAccessor.getConstantsManager();

        Map<String, String> allUserMap  = getAllUserEmailToUsernameMapRecommended();

        Project project = null;
        IssueType issueType = null;
        String priorityId = null;
        Map<String, Object> customFields = new HashMap<>();

        for (Map.Entry<String, Object> entry : fields.entrySet()) {
            String key = entry.getKey();
            Object value = entry.getValue();
            if (value == null) continue;

            switch (key) {
                case "projectKey": {
                    project = projectManager.getProjectObjByKey(String.valueOf(value));
                    if (project == null) throw new RuntimeException("项目不存在: " + value);
                    issueInputParameters.setProjectId(project.getId());
                    break;
                }
                case "issueType": {
                    issueType = findIssueTypeByName(constantsManager, String.valueOf(value));
                    if (issueType == null) throw new RuntimeException("Issue类型不存在: " + value);
                    issueInputParameters.setIssueTypeId(issueType.getId());
                    break;
                }
                case "summary": {
                    issueInputParameters.setSummary(String.valueOf(value));
                    break;
                }
                case "description": {
                    String desc = String.valueOf(value);
                    if (!isBlank(desc)) issueInputParameters.setDescription(desc);
                    break;
                }
                case "priority": {
                    priorityId = findPriorityIdByName(constantsManager, String.valueOf(value));
                    if (priorityId != null) issueInputParameters.setPriorityId(priorityId);
                    break;
                }
                case "assignee": {
                    String assignee = String.valueOf(value);
                    if (!isBlank(assignee)) issueInputParameters.setAssigneeId(changeUserName(assignee, allUserMap));
                    break;
                }
                case "reporter": {
                    String reporter = String.valueOf(value);
                    if (!isBlank(reporter)) issueInputParameters.setReporterId(changeUserName(reporter, allUserMap));
                    break;
                }
                case "duedate": {
                    String s = String.valueOf(value);
                    if (!isBlank(s)) issueInputParameters.setDueDate(normalizeDueDate(s));
                    break;
                }
                default: {
                    if (key.startsWith("customfield_")) customFields.put(key, value);
                    break;
                }
            }
        }

        if (!customFields.isEmpty()) {
            CustomFieldManager customFieldManager = ComponentAccessor.getCustomFieldManager();
            OptionsManager optionsManager = ComponentAccessor.getOptionsManager();

            for (Map.Entry<String, Object> entry : customFields.entrySet()) {
                String fieldName = String.valueOf(entry.getKey());
                Object fieldValue = entry.getValue();
                if (!fieldName.startsWith("customfield")) continue;

                CustomField customField = customFieldManager.getCustomFieldObject(fieldName);
                if (customField == null) throw new RuntimeException("自定义字段不存在: " + fieldName);

                String fieldId = customField.getId();
                String typeKey = customField.getCustomFieldType().getKey();

                switch (typeKey) {
                    case "com.pyxis.greenhopper.jira:gh-sprint": {
                        if (fieldValue != null) {
                            String input = String.valueOf(fieldValue).trim();
                            if (!input.isEmpty()) {
                                String valueToSet = input;
                                if (!input.matches("^\\d+$")) {
                                    List<com.yottastudios.jira.util.SprintHelper.SprintInfo> matched = SprintHelper.fetchSprints(input);
                                    String sprintId = (matched != null && !matched.isEmpty()) ? matched.get(0).getId() : null;
                                    if (sprintId == null || sprintId.trim().isEmpty()) {
                                        if (project != null && "PXM".equalsIgnoreCase(project.getKey())) {
                                            sprintId = SprintHelper.findCurrentVersionSprintPXM();
                                        } else {
                                            sprintId = SprintHelper.findCurrentVersionSprint();
                                        }
                                    }
                                    valueToSet = sprintId == null ? "" : sprintId;
                                }
                                if (!valueToSet.isEmpty()) issueInputParameters.addCustomFieldValue(fieldId, valueToSet);
                            }
                        }
                        break;
                    }
                    case "com.atlassian.jira.plugin.system.customfieldtypes:datepicker":
                    case "com.atlassian.jira.plugin.system.customfieldtypes:datetime": {
                        if (fieldValue != null && !String.valueOf(fieldValue).trim().isEmpty()) {
                            String dateStr = normalizeDueDate(String.valueOf(fieldValue));
                            issueInputParameters.addCustomFieldValue(fieldId, dateStr);
                        }
                        break;
                    }
                    case "com.atlassian.jira.plugin.system.customfieldtypes:userpicker": {
                        if (fieldValue != null) {
                            String username = String.valueOf(fieldValue);
                            issueInputParameters.addCustomFieldValue(fieldId, changeUserName(username, allUserMap));
                        }
                        break;
                    }
                    case "com.atlassian.jira.plugin.system.customfieldtypes:multiuserpicker": {
                        List<String> usernames = new ArrayList<>();
                        if (fieldValue instanceof Collection) {
                            for (Object name : (Collection<?>) fieldValue) usernames.add(String.valueOf(name));
                        } else if (fieldValue != null) {
                            usernames.add(String.valueOf(fieldValue));
                        }
                        if (!usernames.isEmpty()) issueInputParameters.addCustomFieldValue(fieldId, changeUserNameBatch(usernames.toArray(new String[0]), allUserMap));
                        break;
                    }
                    case "com.atlassian.jira.plugin.system.customfieldtypes:select": {
                        if (project == null || issueType == null) throw new RuntimeException("处理选择类自定义字段需要提供projectKey与issueType");
                        IssueContext ctx = new IssueContextImpl(project.getId(), issueType.getId());
                        FieldConfig cfg = customField.getRelevantConfig(ctx);
                        Options options = optionsManager.getOptions(cfg);
                        if (options == null) throw new RuntimeException("未找到选择项: " + customField.getName());

                        Option selected = null;
                        for (Option op : options) {
                            if (Objects.equals(op.getValue(), String.valueOf(fieldValue))) { selected = op; break; }
                        }
                        if (selected == null) throw new RuntimeException("选项不存在: " + fieldValue + " for field: " + customField.getName());
                        issueInputParameters.addCustomFieldValue(fieldId, String.valueOf(selected.getOptionId()));
                        break;
                    }
                    case "com.atlassian.jira.plugin.system.customfieldtypes:multiselect": {
                        if (project == null || issueType == null) throw new RuntimeException("处理选择类自定义字段需要提供projectKey与issueType");
                        IssueContext ctx = new IssueContextImpl(project.getId(), issueType.getId());
                        FieldConfig cfg = customField.getRelevantConfig(ctx);
                        Options options = optionsManager.getOptions(cfg);
                        if (options == null) throw new RuntimeException("未找到选择项: " + customField.getName());

                        List<String> selectedIds = new ArrayList<>();
                        Collection<?> values = (fieldValue instanceof Collection) ? (Collection<?>) fieldValue : Collections.singletonList(String.valueOf(fieldValue));
                        for (Object v : values) {
                            boolean matched = false;
                            for (Option op : options) {
                                if (Objects.equals(op.getValue(), String.valueOf(v))) {
                                    selectedIds.add(String.valueOf(op.getOptionId()));
                                    matched = true;
                                    break;
                                }
                            }
                            if (!matched) throw new RuntimeException("选项不存在: " + v + " for field: " + customField.getName());
                        }
                        issueInputParameters.addCustomFieldValue(fieldId, selectedIds.toArray(new String[0]));
                        break;
                    }
                    default: {
                        issueInputParameters.addCustomFieldValue(fieldId, String.valueOf(fieldValue));
                    }
                }
            }
        }
    }

    private String changeUserNameBatch(String[] userNameList, Map<String, String> allUserMap) {
        return changeUserName(String.join(",", userNameList), allUserMap);
    }

    private String changeUserName(String userNameList, Map<String, String> allUserMap) {
        // userNameList根据","区分, 对每个字段补充@yottastodios.com,如果存在，使用value，不存在使用原值
        String[] userList = userNameList.split(",");
        List<String> transList = new ArrayList<>();
        for(String u : userList){
            String email = u + "@yottastudios.com";
            transList.add(allUserMap.getOrDefault(email, u));
        }
        return String.join(",", transList);
    }

    /**
     * 使用UserSearchService进行用户搜索,获取全部的用户
     */
    private Map<String, String> getAllUserEmailToUsernameMapRecommended() {
        Map<String, String> emailToUsernameMap = new HashMap<>();

        try {
            UserSearchService userSearchService = ComponentAccessor.getComponent(UserSearchService.class);

            // 搜索所有用户，使用空字符串作为查询参数
            UserSearchParams searchParams = UserSearchParams.builder()
                    .allowEmptyQuery(true)
                    .includeActive(true)
                    .includeInactive(false)  // 根据需要可以改为true
                    .maxResults(999)  // 获取所有结果
                    .build();

            List<ApplicationUser> users = userSearchService.findUsers("", searchParams);

            for (ApplicationUser user : users) {
                String email = user.getEmailAddress();
                String username = user.getUsername();

                if (email != null && !email.trim().isEmpty()) {
                    emailToUsernameMap.put(email, username);
                }
            }

        } catch (Exception e) {
            System.err.println("获取用户信息失败: " + e.getMessage());
        }

        return emailToUsernameMap;
    }

    private Issue createIssueWithParameters(ApplicationUser user, Map<String, Object> fields) {
        IssueService issueService = ComponentAccessor.getIssueService();
        IssueInputParameters issueInputParameters = issueService.newIssueInputParameters();

        processFieldsToParameters(fields, issueInputParameters);

        IssueService.CreateValidationResult validationResult = issueService.validateCreate(user, issueInputParameters);
        if (!validationResult.isValid()) {
            String errorDetails = formatErrorCollection(validationResult.getErrorCollection());
            throw new RuntimeException("创建Issue验证失败: " + errorDetails);
        }

        IssueService.IssueResult issueResult = issueService.create(user, validationResult);
        if (!issueResult.isValid()) {
            String errorDetails = formatErrorCollection(issueResult.getErrorCollection());
            throw new RuntimeException("创建Issue失败: " + errorDetails);
        }

        return issueResult.getIssue();
    }

    private IssueType findIssueTypeByName(ConstantsManager constantsManager, String issueTypeName) {
        if (isBlank(issueTypeName)) return null;
        Collection<IssueType> issueTypes = constantsManager.getAllIssueTypeObjects();
        for (IssueType type : issueTypes) {
            if (type.getName().equalsIgnoreCase(issueTypeName)) return type;
        }
        return null;
    }

    private String findPriorityIdByName(ConstantsManager constantsManager, String priorityName) {
        if (isBlank(priorityName)) return null;
        Collection<Priority> priorities = constantsManager.getPriorityObjects();
        for (Priority p : priorities) {
            if (p.getName().equalsIgnoreCase(priorityName)) return p.getId();
        }
        return null;
    }

    private boolean isBlank(String s) {
        return s == null || s.trim().isEmpty();
    }

    private String formatErrorCollection(ErrorCollection errorCollection) {
        Map<String, String> errors = errorCollection.getErrors();
        Collection<String> messages = errorCollection.getErrorMessages();
        StringBuilder sb = new StringBuilder();
        if (errors != null && !errors.isEmpty()) {
            String joined = errors.entrySet()
                    .stream()
                    .map(e -> e.getKey() + "=" + e.getValue())
                    .collect(Collectors.joining("; "));
            sb.append(joined);
        }
        if (messages != null && !messages.isEmpty()) {
            String joinedMsgs = String.join("; ", messages);
            if (sb.length() > 0) sb.append("; ");
            sb.append(joinedMsgs);
        }
        return sb.toString();
    }

    private String normalizeDueDate(String input) {
        String s = input == null ? null : input.trim();
        if (isBlank(s)) return s;
        List<String> patterns = Arrays.asList(
            "yyyy-MM-dd",
            "yyyy/MM/dd",
            "yyyy.MM.dd",
            "yyyy-MM-dd HH:mm:ss",
            "yyyy/MM/dd HH:mm:ss",
            "d/MMM/yy",
            "dd/MMM/yy"
        );
        List<Locale> locales = Arrays.asList(Locale.CHINA, Locale.SIMPLIFIED_CHINESE, Locale.ENGLISH, Locale.getDefault());
        for (Locale loc : locales) {
            for (String p : patterns) {
                try {
                    SimpleDateFormat parser = new SimpleDateFormat(p, loc);
                    parser.setLenient(false);
                    Date dt = parser.parse(s);
                    SimpleDateFormat formatter = new SimpleDateFormat("yyyy/MM/dd", Locale.CHINA);
                    return formatter.format(dt);
                } catch (Exception ignored) {
                }
            }
        }
        // 如果无法解析，原样返回，让Jira给出校验错误
        return s;
    }


    /**
     * 创建Issue之间的链接
     */
    private void createIssueLink(String sourceIssueKey, String targetIssueKey, String linkTypeName, ApplicationUser user) throws Exception {
        log.warn("create Link: {}, from {}, to {}", linkTypeName, sourceIssueKey, targetIssueKey);
        if (isBlank(sourceIssueKey)) throw new RuntimeException("源IssueKey不能为空");
        if (isBlank(targetIssueKey)) throw new RuntimeException("目标IssueKey不能为空");
        if (isBlank(linkTypeName)) throw new RuntimeException("链接类型名称不能为空");

        IssueManager issueManager = ComponentAccessor.getIssueManager();
        Issue source = issueManager.getIssueObject(sourceIssueKey);
        if (source == null) throw new RuntimeException("找不到源Issue: " + sourceIssueKey);
        Issue target = issueManager.getIssueObject(targetIssueKey);
        if (target == null) throw new RuntimeException("找不到目标Issue: " + targetIssueKey);

        IssueLinkTypeManager issueLinkTypeManager = ComponentAccessor.getComponent(IssueLinkTypeManager.class);
        IssueLinkType linkType = findLinkTypeByName(issueLinkTypeManager, linkTypeName);
        if (linkType == null) throw new RuntimeException("未找到链接类型: " + linkTypeName);

        IssueLinkManager issueLinkManager = ComponentAccessor.getIssueLinkManager();
        issueLinkManager.createIssueLink(
            source.getId(),
            target.getId(),
            linkType.getId(),
            1L,
            user
        );
    }

    /**
     * 根据名称查找链接类型
     */
    private IssueLinkType findLinkTypeByName(IssueLinkTypeManager issueLinkTypeManager, String linkTypeName) {
        try {
            Collection<IssueLinkType> linkTypes = issueLinkTypeManager.getIssueLinkTypes();

            // 首先尝试精确匹配
            for (IssueLinkType linkType : linkTypes) {
                if (linkType.getName().equalsIgnoreCase(linkTypeName) || 
                    linkType.getOutward().equalsIgnoreCase(linkTypeName) || 
                    linkType.getInward().equalsIgnoreCase(linkTypeName)) {
                    return linkType;
                }
            }

            // 如果没有精确匹配，尝试部分匹配
            for (IssueLinkType linkType : linkTypes) {
                if (linkType.getName().toLowerCase().contains(linkTypeName.toLowerCase()) || 
                    linkType.getOutward().toLowerCase().contains(linkTypeName.toLowerCase()) || 
                    linkType.getInward().toLowerCase().contains(linkTypeName.toLowerCase())) {
                    return linkType;
                }
            }
        } catch (Exception e) {
            log.warn("查找链接类型时出错: " + e.getMessage(), e);
        }

        return null;
    }

    // Template handlers
    private TemplateVo createTemplate(HttpServletRequest request) throws Exception {
        UserProfile user = userManager.getRemoteUser(request);
        if (user == null) throw new RuntimeException("未登录");
        TemplateCreateRo ro = readJsonBody(request, TemplateCreateRo.class);
        if (ro == null) throw new RuntimeException("请求体不能为空");
        if (ro.getName() == null || ro.getName().trim().isEmpty()) throw new RuntimeException("name不能为空");
        if (ro.getGroupId() <= 0) throw new RuntimeException("groupId非法");
        // 校验 groupId 是否存在
        TemplateGroup group = templateGroupMapper.getById(ro.getGroupId());
        if (group == null) throw new RuntimeException("group不存在");

        String projectKey = ro.getProjectKey();
        // 校验 projectKey 是否存在（只有在有值时才校验）
        if (projectKey != null && !projectKey.trim().isEmpty()) {
            ProjectManager pm = ComponentAccessor.getProjectManager();
            Project pj = pm.getProjectObjByKey(projectKey.trim());
            if (pj == null) throw new RuntimeException("project不存在: " + projectKey);
            projectKey = projectKey.trim();
        } else {
            projectKey = "";
        }

        Template t = templateMapper.create(projectKey, ro.getName().trim(), ro.getGroupId());
        return TemplateVo.from(t);
    }

    private TemplateVo updateTemplate(HttpServletRequest request) throws Exception {
        UserProfile user = userManager.getRemoteUser(request);
        if (user == null) throw new RuntimeException("未登录");
        TemplateUpdateRo ro = readJsonBody(request, TemplateUpdateRo.class);
        if (ro == null || ro.getId() <= 0) throw new RuntimeException("非法ID");
        if (ro.getName() == null || ro.getName().trim().isEmpty()) throw new RuntimeException("name不能为空");

        String projectKey = ro.getProjectKey();
