 630→            List<Long> ups = item.getUpstreamIssueTemplateIds();
 631→            if (ups != null) {
 632→                for (Long up : ups) {
 633→                    if (up == null) continue;
 634→                    String upKey = templateIdToIssueKey.get(up);
 635→                    if (upKey == null) throw new RuntimeException("内部错误：未找到依赖创建结果: " + up);
 636→                    createIssueLink(created.getKey(), upKey, LINK_TYPE_UPSTREAM, applicationUser);
