 638→            }
 639→
 640→            if (item.getLinks() != null) {
 641→                Set<String> autoPairs = new HashSet<>();
 642→                if (parent != null) autoPairs.add(LINK_TYPE_PARENT + "@" + templateIdToIssueKey.get(parent));
 643→                if (ups != null) {
 644→                    for (Long up : ups) {
 645→                        if (up == null) continue;
