 647→                        if (upKey != null) autoPairs.add(LINK_TYPE_UPSTREAM + "@" + upKey);
 648→                    }
 649→                }
 650→                for (LinkCreateRo link : item.getLinks()) {
 651→                    if (link == null) continue;
 652→                    String type = link.getLinkTypeName();
 653→                    String tgt = link.getTargetIssueKey();
 654→                    if (isBlank(type) || isBlank(tgt)) continue;
