 656→                    if (autoPairs.contains(pair)) continue;
 657→                    createIssueLink(created.getKey(), tgt, type, applicationUser);
 658→                }
 659→            }
 660→
 661→            templateIdToIssueKey.put(id, created.getKey());
 662→            results.add(new CreatedIssueInfo(created.getKey(), created.getId()));
 663→        }
 664→
 665→        return results;
