1045→    private void processFieldsToParameters(Map<String, Object> fields, IssueInputParameters issueInputParameters) {
1046→        ProjectManager projectManager = ComponentAccessor.getProjectManager();
1047→        ConstantsManager constantsManager = ComponentAccessor.getConstantsManager();
1048→
1049→        Map<String, String> allUserMap  = getAllUserEmailToUsernameMapRecommended();
1050→
1051→        Project project = null;
1052→        IssueType issueType = null;
1053→        String priorityId = null;
1054→        Map<String, Object> customFields = new HashMap<>();
1055→
1056→        for (Map.Entry<String, Object> entry : fields.entrySet()) {
1057→            String key = entry.getKey();
1058→            Object value = entry.getValue();
1059→            if (value == null) continue;
1060→
1061→            switch (key) {
1062→                case "projectKey": {
1063→                    project = projectManager.getProjectObjByKey(String.valueOf(value));
1064→                    if (project == null) throw new RuntimeException("项目不存在: " + value);
1065→                    issueInputParameters.setProjectId(project.getId());
1066→                    break;
1067→                }
1068→                case "issueType": {
1069→                    issueType = findIssueTypeByName(constantsManager, String.valueOf(value));
1070→                    if (issueType == null) throw new RuntimeException("Issue类型不存在: " + value);
1071→                    issueInputParameters.setIssueTypeId(issueType.getId());
1072→                    break;
1073→                }
1074→                case "summary": {
1075→                    issueInputParameters.setSummary(String.valueOf(value));
1076→                    break;
1077→                }
1078→                case "description": {
1079→                    String desc = String.valueOf(value);
1080→                    if (!isBlank(desc)) issueInputParameters.setDescription(desc);
1081→                    break;
1082→                }
1083→                case "priority": {
1084→                    priorityId = findPriorityIdByName(constantsManager, String.valueOf(value));
1085→                    if (priorityId != null) issueInputParameters.setPriorityId(priorityId);
1086→                    break;
1087→                }
1088→                case "assignee": {
1089→                    String assignee = String.valueOf(value);
1090→                    if (!isBlank(assignee)) issueInputParameters.setAssigneeId(changeUserName(assignee, allUserMap));
1091→                    break;
1092→                }
1093→                case "reporter": {
1094→                    String reporter = String.valueOf(value);
1095→                    if (!isBlank(reporter)) issueInputParameters.setReporterId(changeUserName(reporter, allUserMap));
1096→                    break;
1097→                }
1098→                case "duedate": {
1099→                    String s = String.valueOf(value);
1100→                    if (!isBlank(s)) issueInputParameters.setDueDate(normalizeDueDate(s));
1101→                    break;
1102→                }
1103→                default: {
1104→                    if (key.startsWith("customfield_")) customFields.put(key, value);
1105→                    break;
1106→                }
1107→            }
1108→        }
1109→
1110→        if (!customFields.isEmpty()) {
1111→            CustomFieldManager customFieldManager = ComponentAccessor.getCustomFieldManager();
1112→            OptionsManager optionsManager = ComponentAccessor.getOptionsManager();
1113→
1114→            for (Map.Entry<String, Object> entry : customFields.entrySet()) {
1115→                String fieldName = String.valueOf(entry.getKey());
1116→                Object fieldValue = entry.getValue();
1117→                if (!fieldName.startsWith("customfield")) continue;
1118→
1119→                CustomField customField = customFieldManager.getCustomFieldObject(fieldName);
1120→                if (customField == null) throw new RuntimeException("自定义字段不存在: " + fieldName);
1121→
1122→                String fieldId = customField.getId();
1123→                String typeKey = customField.getCustomFieldType().getKey();
1124→
1125→                switch (typeKey) {
1126→                    case "com.pyxis.greenhopper.jira:gh-sprint": {
1127→                        if (fieldValue != null) {
1128→                            String input = String.valueOf(fieldValue).trim();
1129→                            if (!input.isEmpty()) {
1130→                                String valueToSet = input;
1131→                                if (!input.matches("^\\d+$")) {
1132→                                    List<com.yottastudios.jira.util.SprintHelper.SprintInfo> matched = SprintHelper.fetchSprints(input);
1133→                                    String sprintId = (matched != null && !matched.isEmpty()) ? matched.get(0).getId() : null;
1134→                                    if (sprintId == null || sprintId.trim().isEmpty()) {
1135→                                        if (project != null && "PXM".equalsIgnoreCase(project.getKey())) {
1136→                                            sprintId = SprintHelper.findCurrentVersionSprintPXM();
1137→                                        } else {
1138→                                            sprintId = SprintHelper.findCurrentVersionSprint();
1139→                                        }
1140→                                    }
1141→                                    valueToSet = sprintId == null ? "" : sprintId;
1142→                                }
1143→                                if (!valueToSet.isEmpty()) issueInputParameters.addCustomFieldValue(fieldId, valueToSet);
1144→                            }
1145→                        }
1146→                        break;
1147→                    }
1148→                    case "com.atlassian.jira.plugin.system.customfieldtypes:datepicker":
1149→                    case "com.atlassian.jira.plugin.system.customfieldtypes:datetime": {
1150→                        if (fieldValue != null && !String.valueOf(fieldValue).trim().isEmpty()) {
1151→                            String dateStr = normalizeDueDate(String.valueOf(fieldValue));
1152→                            issueInputParameters.addCustomFieldValue(fieldId, dateStr);
1153→                        }
1154→                        break;
1155→                    }
1156→                    case "com.atlassian.jira.plugin.system.customfieldtypes:userpicker": {
1157→                        if (fieldValue != null) {
1158→                            String username = String.valueOf(fieldValue);
1159→                            issueInputParameters.addCustomFieldValue(fieldId, changeUserName(username, allUserMap));
1160→                        }
1161→                        break;
1162→                    }
1163→                    case "com.atlassian.jira.plugin.system.customfieldtypes:multiuserpicker": {
1164→                        List<String> usernames = new ArrayList<>();
1165→                        if (fieldValue instanceof Collection) {
1166→                            for (Object name : (Collection<?>) fieldValue) usernames.add(String.valueOf(name));
1167→                        } else if (fieldValue != null) {
1168→                            usernames.add(String.valueOf(fieldValue));
1169→                        }
1170→                        if (!usernames.isEmpty()) issueInputParameters.addCustomFieldValue(fieldId, changeUserNameBatch(usernames.toArray(new String[0]), allUserMap));
1171→                        break;
1172→                    }
1173→                    case "com.atlassian.jira.plugin.system.customfieldtypes:select": {
1174→                        if (project == null || issueType == null) throw new RuntimeException("处理选择类自定义字段需要提供projectKey与issueType");
1175→                        IssueContext ctx = new IssueContextImpl(project.getId(), issueType.getId());
1176→                        FieldConfig cfg = customField.getRelevantConfig(ctx);
1177→                        Options options = optionsManager.getOptions(cfg);
1178→                        if (options == null) throw new RuntimeException("未找到选择项: " + customField.getName());
1179→
1180→                        Option selected = null;
1181→                        for (Option op : options) {
1182→                            if (Objects.equals(op.getValue(), String.valueOf(fieldValue))) { selected = op; break; }
1183→                        }
1184→                        if (selected == null) throw new RuntimeException("选项不存在: " + fieldValue + " for field: " + customField.getName());
1185→                        issueInputParameters.addCustomFieldValue(fieldId, String.valueOf(selected.getOptionId()));
1186→                        break;
1187→                    }
1188→                    case "com.atlassian.jira.plugin.system.customfieldtypes:multiselect": {
1189→                        if (project == null || issueType == null) throw new RuntimeException("处理选择类自定义字段需要提供projectKey与issueType");
1190→                        IssueContext ctx = new IssueContextImpl(project.getId(), issueType.getId());
1191→                        FieldConfig cfg = customField.getRelevantConfig(ctx);
1192→                        Options options = optionsManager.getOptions(cfg);
1193→                        if (options == null) throw new RuntimeException("未找到选择项: " + customField.getName());
1194→
1195→                        List<String> selectedIds = new ArrayList<>();
1196→                        Collection<?> values = (fieldValue instanceof Collection) ? (Collection<?>) fieldValue : Collections.singletonList(String.valueOf(fieldValue));
1197→                        for (Object v : values) {
1198→                            boolean matched = false;
1199→                            for (Option op : options) {
1200→                                if (Objects.equals(op.getValue(), String.valueOf(v))) {
1201→                                    selectedIds.add(String.valueOf(op.getOptionId()));
1202→                                    matched = true;
1203→                                    break;
1204→                                }
1205→                            }
1206→                            if (!matched) throw new RuntimeException("选项不存在: " + v + " for field: " + customField.getName());
1207→                        }
1208→                        issueInputParameters.addCustomFieldValue(fieldId, selectedIds.toArray(new String[0]));
1209→                        break;
1210→                    }
1211→                    default: {
1212→                        issueInputParameters.addCustomFieldValue(fieldId, String.valueOf(fieldValue));
1213→                    }
1214→                }
1215→            }
1216→        }
1217→    }
