1312→    private String formatErrorCollection(ErrorCollection errorCollection) {
1313→        Map<String, String> errors = errorCollection.getErrors();
1314→        Collection<String> messages = errorCollection.getErrorMessages();
1315→        StringBuilder sb = new StringBuilder();
1316→        if (errors != null && !errors.isEmpty()) {
1317→            String joined = errors.entrySet()
1318→                    .stream()
1319→                    .map(e -> e.getKey() + "=" + e.getValue())
1320→                    .collect(Collectors.joining("; "));
1321→            sb.append(joined);
1322→        }
1323→        if (messages != null && !messages.isEmpty()) {
1324→            String joinedMsgs = String.join("; ", messages);
1325→            if (sb.length() > 0) sb.append("; ");
1326→            sb.append(joinedMsgs);
1327→        }
1328→        return sb.toString();
1329→    }
