1331→    private String normalizeDueDate(String input) {
1332→        String s = input == null ? null : input.trim();
1333→        if (isBlank(s)) return s;
1334→        List<String> patterns = Arrays.asList(
1335→            "yyyy-MM-dd",
1336→            "yyyy/MM/dd",
1337→            "yyyy.MM.dd",
1338→            "yyyy-MM-dd HH:mm:ss",
1339→            "yyyy/MM/dd HH:mm:ss",
1340→            "d/MMM/yy",
1341→            "dd/MMM/yy"
1342→        );
1343→        List<Locale> locales = Arrays.asList(Locale.CHINA, Locale.SIMPLIFIED_CHINESE, Locale.ENGLISH, Locale.getDefault());
1344→        for (Locale loc : locales) {
1345→            for (String p : patterns) {
1346→                try {
1347→                    SimpleDateFormat parser = new SimpleDateFormat(p, loc);
1348→                    parser.setLenient(false);
1349→                    Date dt = parser.parse(s);
1350→                    SimpleDateFormat formatter = new SimpleDateFormat("yyyy/MM/dd", Locale.CHINA);
1351→                    return formatter.format(dt);
1352→                } catch (Exception ignored) {
1353→                }
1354→            }
1355→        }
1356→        // 如果无法解析，原样返回，让Jira给出校验错误
1357→        return s;
1358→    }
