package com.yottastudios.jira.mapper;

import com.atlassian.activeobjects.external.ActiveObjects;
import com.atlassian.plugin.spring.scanner.annotation.imports.ComponentImport;
import com.yottastudios.jira.ao.IssueTemplate;
import net.java.ao.DBParam;
import net.java.ao.Query;

import javax.inject.Inject;
import javax.inject.Named;

@Named
public class IssueTemplateMapper {
    @ComponentImport
    private final ActiveObjects ao;

    @Inject
    public IssueTemplateMapper(ActiveObjects ao) {
        this.ao = ao;
    }

    public IssueTemplate create(int templateId, String fields, Integer orderNo, Integer parentIssueTemplateId, String upstreamIssueTemplateIds) {
        String safeFields = fields == null ? "" : fields;
        String ids = (upstreamIssueTemplateIds == null) ? "" : upstreamIssueTemplateIds.trim();
        return ao.create(IssueTemplate.class,
                new DBParam("TEMPLATE_ID", templateId),
                new DBParam("FIELDS", safeFields),
                new DBParam("UPSTREAM_ISSUE_TEMPLATE_ID", 0),
                new DBParam("UPSTREAM_ISSUE_TEMPLATE_IDS", ids),
                new DBParam("PARENT_ISSUE_TEMPLATE_ID", parentIssueTemplateId == null ? 0 : parentIssueTemplateId),
                new DBParam("ORDER_NO", orderNo == null ? 0 : orderNo));
    }

    public IssueTemplate update(int id, String fields, Integer parentIssueTemplateId, String upstreamIssueTemplateIds) {
        IssueTemplate it = ao.get(IssueTemplate.class, id);
        if (it == null) return null;
        it.setFields(fields == null ? "" : fields);
        it.setUpstreamIssueTemplateIds(upstreamIssueTemplateIds == null ? "" : upstreamIssueTemplateIds.trim());
        it.setUpstreamIssueTemplateId(0);
        it.setParentIssueTemplateId(parentIssueTemplateId == null ? 0 : parentIssueTemplateId);
        it.save();
        return it;
    }

    public boolean deleteById(int id) {
        IssueTemplate it = ao.get(IssueTemplate.class, id);
        if (it == null) return false;
        ao.delete(it);
        return true;
    }

    public IssueTemplate[] listByTemplateId(int templateId) {
        return ao.find(IssueTemplate.class, Query.select().where("TEMPLATE_ID = ?", templateId));
    }

    public IssueTemplate getById(int id) {
        return ao.get(IssueTemplate.class, id);
    }

    public int getMaxOrderNoByTemplateId(int templateId) {
        IssueTemplate[] arr = ao.find(IssueTemplate.class, Query.select().where("TEMPLATE_ID = ?", templateId));
        int max = 0;
        for (IssueTemplate it : arr) max = Math.max(max, it.getOrderNo());
        return max;
    }
}

