    private IssueTemplateVo createIssueTemplate(HttpServletRequest request) throws Exception {
        UserProfile user = userManager.getRemoteUser(request);
        if (user == null) throw new RuntimeException("未登录");
        IssueTemplateCreateRo ro = readJsonBody(request, IssueTemplateCreateRo.class);
        if (ro == null) throw new RuntimeException("请求体不能为空");
        if (ro.getTemplateId() <= 0) throw new RuntimeException("templateId非法");
        // 校验 template 是否存在
        Template template = templateMapper.getById(ro.getTemplateId());
        if (template == null) throw new RuntimeException("template不存在");
        // 创建
        int nextOrder = issueTemplateMapper.getMaxOrderNoByTemplateId(ro.getTemplateId()) + 1;
        if (nextOrder <= 0) nextOrder = 1;
        IssueTemplate it = issueTemplateMapper.create(
                ro.getTemplateId(),
                ro.getFields(),
                nextOrder,
                ro.getParentIssueTemplateId(),
                (ro.getUpstreamIssueTemplateIds() == null || ro.getUpstreamIssueTemplateIds().isEmpty())
                        ? ""
                        : ro.getUpstreamIssueTemplateIds().stream().map(String::valueOf).collect(java.util.stream.Collectors.joining(","))
        );
        return IssueTemplateVo.from(it);
    }

    private IssueTemplateVo updateIssueTemplate(HttpServletRequest request) throws Exception {
        UserProfile user = userManager.getRemoteUser(request);
        if (user == null) throw new RuntimeException("未登录");
        IssueTemplateUpdateRo ro = readJsonBody(request, IssueTemplateUpdateRo.class);
        if (ro == null || ro.getId() <= 0) throw new RuntimeException("非法ID");
        IssueTemplate updated = issueTemplateMapper.update(
                ro.getId(),
                ro.getFields(),
                ro.getParentIssueTemplateId(),
                (ro.getUpstreamIssueTemplateIds() == null || ro.getUpstreamIssueTemplateIds().isEmpty())
                        ? ""
                        : ro.getUpstreamIssueTemplateIds().stream().map(String::valueOf).collect(java.util.stream.Collectors.joining(","))
        );
        if (updated == null) throw new RuntimeException("记录不存在");
        return IssueTemplateVo.from(updated);
    }

    private JSONObject deleteIssueTemplate(HttpServletRequest request) throws Exception {
        UserProfile user = userManager.getRemoteUser(request);
        if (user == null) throw new RuntimeException("未登录");
        IssueTemplateDeleteRo ro = readJsonBody(request, IssueTemplateDeleteRo.class);
        if (ro == null || ro.getId() <= 0) throw new RuntimeException("非法ID");
        boolean success = issueTemplateMapper.deleteById(ro.getId());
        JSONObject obj = new JSONObject();
        obj.put("success", success);
        return obj;
    }

    private List<IssueTemplateVo> listIssueTemplatesByTemplate(HttpServletRequest request) throws Exception {
        UserProfile user = userManager.getRemoteUser(request);
        if (user == null) throw new RuntimeException("未登录");
        IssueTemplateListRo ro = readJsonBody(request, IssueTemplateListRo.class);
        if (ro == null || ro.getTemplateId() <= 0) throw new RuntimeException("templateId非法");
        // 校验 template 是否存在
        Template template = templateMapper.getById(ro.getTemplateId());
        if (template == null) throw new RuntimeException("template不存在");
        IssueTemplate[] arr = issueTemplateMapper.listByTemplateId(ro.getTemplateId());
        List<IssueTemplateVo> list = new ArrayList<>();
        for (IssueTemplate it : arr) list.add(IssueTemplateVo.from(it));
        return list;
    }


}

