/**
 * 显示Excel预览
 */
function showExcelPreview(fileName, data) {
    var previewElement = document.getElementById("excel-preview");
    var dataElement = document.getElementById("excel-data");

    if (!previewElement || !dataElement) return;

    // 清空当前内容，但保留行操作按钮容器和列操作按钮容器
    var rowActions = dataElement.querySelector('.row-actions');
    var columnActions = dataElement.querySelector('.column-actions');
    dataElement.innerHTML = '';
    if (rowActions) {
        dataElement.appendChild(rowActions);
    }
    if (columnActions) {
        dataElement.appendChild(columnActions);
    }

    if (!data || data.length === 0) {
        dataElement.innerHTML = '<div class="aui-message aui-message-warning"><p>Excel文件没有数据</p></div>';
        previewElement.style.display = "block";
        return;
    }

    // 创建表格
    var table = document.createElement('table');
    var thead = document.createElement('thead');
    var tbody = document.createElement('tbody');
    var headerRow = document.createElement('tr');

    // 添加表头 - 使用第一行作为列标题
    var firstRow = data[0];
    for (var i = 0; i < firstRow.length; i++) {
        var th = document.createElement('th');
        th.textContent = firstRow[i] || '列 ' + (i + 1);
        th.setAttribute('data-original', firstRow[i] || '列 ' + (i + 1));
        th.addEventListener('click', handleCellEdit); // 添加表头编辑功能
        headerRow.appendChild(th);
    }

    // 添加操作列表头
    var actionTh = document.createElement('th');
    actionTh.style.width = '30px';
    actionTh.style.background = 'transparent';
    actionTh.style.border = 'none';
    headerRow.appendChild(actionTh);

    thead.appendChild(headerRow);
    table.appendChild(thead);

    // 添加数据行 - 从第二行开始，如果存在的话
    if (data.length > 1) {
        for (var rowIndex = 1; rowIndex < data.length; rowIndex++) {
            var tr = document.createElement('tr');
            var row = data[rowIndex];

            // 检查是否是空行
            var isEmptyRow = true;
            for (var cellIndex = 0; cellIndex < row.length; cellIndex++) {
                if (row[cellIndex] && row[cellIndex].trim() !== '') {
                    isEmptyRow = false;
                    break;
                }
            }

            // 添加单元格
            for (var cellIndex = 0; cellIndex < row.length; cellIndex++) {
                var td = document.createElement('td');
                td.textContent = row[cellIndex];
                td.setAttribute('data-original', row[cellIndex]);
                td.addEventListener('click', handleCellEdit);
                tr.appendChild(td);
            }

            // 添加操作单元格和删除按钮
            var actionTd = document.createElement('td');
            actionTd.className = 'action-cell';

            var deleteBtn = document.createElement('button');
            deleteBtn.className = 'row-delete-btn';
            deleteBtn.innerHTML = '-';
            deleteBtn.setAttribute('title', '删除行');
            deleteBtn.addEventListener('click', function(e) {
                e.stopPropagation();
                var row = this.closest('tr');
                if (row) {
                    row.parentNode.removeChild(row);
                }
            });

            actionTd.appendChild(deleteBtn);
            tr.appendChild(actionTd);

            tbody.appendChild(tr);
        }
    } else {
        // 如果只有表头行，添加一个空行
        var tr = document.createElement('tr');
        for (var i = 0; i < firstRow.length; i++) {
            var td = document.createElement('td');
            td.textContent = '';
            td.setAttribute('data-original', '');
            td.addEventListener('click', handleCellEdit);
            tr.appendChild(td);
        }

        // 添加操作单元格和删除按钮
        var actionTd = document.createElement('td');
        actionTd.className = 'action-cell';

        var deleteBtn = document.createElement('button');
        deleteBtn.className = 'row-delete-btn';
        deleteBtn.innerHTML = '-';
        deleteBtn.setAttribute('title', '删除行');
        deleteBtn.addEventListener('click', function(e) {
            e.stopPropagation();
            var row = this.closest('tr');
            if (row) {
                row.parentNode.removeChild(row);
            }
        });

        actionTd.appendChild(deleteBtn);
        tr.appendChild(actionTd);

        tbody.appendChild(tr);
    }

    table.appendChild(tbody);

    // 添加文件名信息
    var fileInfo = document.createElement('p');
    fileInfo.innerHTML = '<strong>文件名:</strong> ' + fileName;

    // 将元素添加到页面

